svg.script:
(() => {
  "use strict";
  const svg = document.getElementById("mini-stage");

  // ── 可调参数(tuner state)──
  const state = {
    cycle: 4,                // 2026-06-15 鹿鹿拍板:客户「太木」反馈把节奏从主线 5.6s 调到 4s,与放大幅度配套(快节奏深呼吸);原口径「主线 sleeping-loop 5.6s 同款」已让位给客户「幅度大」要求
    tilt: 7, tiltBreath: 7.1,  // 头耷角(正值=耷拉程度,apply 取负——呆毛重力同口径)+ 吸气微抬。tiltBreath 2026-06-15 鹿鹿拍板 7.1°(原 1°,客户「太木」反馈;视觉=深呼吸吸气脖子伸直,峰值头抬到水平 +0.1°,几乎归零非反向穿帮);滑块上限 8°
    breathAmp: 5,            // 身体呼吸系数(×主线 0.024/0.018/1.6)。2026-06-15 鹿鹿拍板 ×5(原 1,客户「喜欢幅度大的」反馈;远端扰动 ~17px,sx ±12%/sy ±9%);滑块上限 5
    zzzX: 52, zzzY: 86, zzzScale: 1, zzzColor: 0,  // 锚=冒出点(贴上耳,屏幕系上耳(30,131)),鹿鹿二轮:别遮脑袋
    mouthInset: 16, mouthWobble: 2,  // 主线睡觉 19→22 = base+3*t 同语义
    browLift: 4,                     // 眉毛放松上移(离墨镜更远,鹿鹿二轮)
    tuftFloat: 1.5,
    tieSway: 0.4
  };
  const TILT_PIVOT = { x: 187, y: 252 };   // 脖根(alert 摆心同款)
  const TIE_PIVOT = { x: 186.5, y: 279 };  // 领结中心母版系(153+33.5, 260+5+14)

  // Zzz 三段:错相/淡入淡出/飘移节奏 = 主线 sleeping-loop zzzParts 搬运(dx 取负=往屏幕内上方飘)。
  // 鹿鹿二轮重排:锚(zzzX/zzzY)=冒出点贴上耳(屏幕系上耳(30,131)),小 Z 先冒(delay 0),
  // 中/大 Z 依次往左上逐级飘大——「一颗 z 从耳朵冒出来越飘越大」,默认全程不压头盖(head-cap y≥107)。
  const ZZZ_PARTS = [
    { id: "sleep-zzz-small", relX: 0,   relY: 0,   delay: 0,    dx: -5, dy: -10, scale0: 0.62 },
    { id: "sleep-zzz-mid",   relX: -28, relY: -38, delay: 0.23, dx: -7, dy: -13, scale0: 0.68 },
    { id: "sleep-zzz-large", relX: -52, relY: -85, delay: 0.46, dx: -9, dy: -16, scale0: 0.72 }
  ];
  const ZZZ_PALETTES = [
    { name: "暖棕", color: "#8a5a3f" },   // 主线 sleeping-loop 同款
    { name: "灰蓝", color: "#5a6a8a" },
    { name: "青蓝", color: "#4fb8d8" }    // alert 音波系
  ];

  // ── 工具(主线 sleeping-loop / alert tuner 同款)──
  function clamp(v, a, b) { return Math.max(a, Math.min(b, v)); }
  function lerp(a, b, t) { return a + (b - a) * t; }
  function fract(v) { return v - Math.floor(v); }
  function easeOutCubic(v) { const t = clamp(v, 0, 1); return 1 - Math.pow(1 - t, 3); }
  function easeBreath(linear) { return (1 - Math.cos(linear * Math.PI * 2)) / 2; }
  function fmt(v) { return String(parseFloat(Number(v).toFixed(2))); }
  function fmtFine(v) { return String(parseFloat(Number(v).toFixed(4))); }
  function setT(id, transform) {
    const node = svg.querySelector(`#${id}`);
    if (node) {
      if (transform) node.setAttribute("transform", transform);
      else node.removeAttribute("transform");
    }
  }

  // thinking 定稿闭嘴收口搬运(alert 同款 applyMouthInset)
  function applyMouthInset(inset) {
    ["mouth-left", "mouth-right"].forEach((id) => {
      const node = svg.querySelector(`#${id}`);
      if (!node || !node.getTotalLength) return;
      if (inset <= .01) {
        node.removeAttribute("stroke-dasharray");
        node.removeAttribute("stroke-dashoffset");
        return;
      }
      const length = node.getTotalLength();
      const visibleLength = Math.max(.1, length - inset);
      node.setAttribute("stroke-dasharray", `${fmt(visibleLength)} ${fmt(length + 24)}`);
      node.setAttribute("stroke-dashoffset", "0");
    });
  }

  // ── 每帧 ──
  const zzzLayer = document.getElementById("sleep-zzz-layer");
  let t0 = performance.now();
  function frame(now) {
    const phase = fract((now - t0) / 1000 / state.cycle);
    const t = easeBreath(phase);   // 0..1..0 正弦呼吸(主线同款)

    // 身体呼吸:主线串逐字 ×幅度系数(横躺后视觉=躺着肚子起伏,方向数学自洽)
    const a = state.breathAmp;
    const sx = 1 + 0.024 * a * t;
    const sy = 1 - 0.018 * a * t;
    const by = 1.6 * a * t;
    setT("sleep-body-breath",
      `translate(187 322) translate(0 ${fmtFine(by)}) scale(${fmtFine(sx)} ${fmtFine(sy)}) translate(-187 -322)`);

    // 头耷:静态耷角 + 吸气微抬;屏幕系下垂=母版负角(呆毛重力同款取负)
    const tiltDeg = -(state.tilt - state.tiltBreath * t);
    setT("sleep-head-tilt", Math.abs(tiltDeg) > .01
      ? `rotate(${fmt(tiltDeg)} ${TILT_PIVOT.x} ${TILT_PIVOT.y})` : "");

    // 呆毛缓飘:底座重力角 -32 上叠加,与呼吸同周期,两根错相(alert 错相先例)
    const fl = Math.sin(2 * Math.PI * phase) * state.tuftFloat;
    const fr = Math.sin(2 * Math.PI * phase + .9) * state.tuftFloat;
    setT("left-tuft", `rotate(${fmt(-32 + fl)} 182 49)`);
    setT("right-tuft", `rotate(${fmt(-32 + fr)} 200 50)`);

    // 领带微摆:主线 tieLag(phase+0.08 滞后)语义,对称小角,可关 0
    if (state.tieSway > .01) {
      const lag = easeBreath(fract(phase + 0.08));
      const sway = state.tieSway * (lag * 2 - 1);
      setT("sleep-tie-sway", `rotate(${fmt(sway)} ${TIE_PIVOT.x} ${TIE_PIVOT.y})`);
    } else {
      setT("sleep-tie-sway", "");
    }

    // 嘴:睡觉小嘴 + 呼吸波动(主线 19→22 同语义 base+wobble*t)
    applyMouthInset(state.mouthInset + state.mouthWobble * t);

    // 眉毛放松上移(鹿鹿二轮:离墨镜更远;眉形已换主线 sleeping 对称放松拱,母版系 y- = 远离镜框)
    const browT = state.browLift > .01 ? `translate(0 ${fmt(-state.browLift)})` : "";
    setT("left-brow", browT);
    setT("right-brow", browT);

    // Zzz 三段错相(主线 render 的 zzz 段逐字:appear/fade/rise/scale)
    for (const part of ZZZ_PARTS) {
      const node = document.getElementById(part.id);
      if (!node) continue;
      const p = fract(phase - part.delay);
      const appear = easeOutCubic(p / 0.24);
      const fade = clamp((p - 0.64) / 0.24, 0, 1);
      const alpha = 0.9 * appear * (1 - fade);
      const rise = easeOutCubic(p / 0.9);
      const s = lerp(part.scale0, 1, appear) * state.zzzScale;
      const x = state.zzzX + part.relX * state.zzzScale + part.dx * rise;
      const y = state.zzzY + part.relY * state.zzzScale + part.dy * rise;
      node.setAttribute("transform", `translate(${fmt(x)} ${fmt(y)}) scale(${fmt(s)})`);
      node.setAttribute("opacity", fmt(alpha));
    }
    zzzLayer.setAttribute("stroke", ZZZ_PALETTES[state.zzzColor].color);

    refreshJson();
    requestAnimationFrame(frame);
  }

  function refreshJson() {} // 面板已剥离(导出无 tuner)

  requestAnimationFrame(frame);
  window.__miniSleep = { state };
})();
